use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

/// Rounds a real number to 6 significant digits.
fn round_to_6_sig(x: f64) -> f64 {
    if x == 0.0 {
        return 0.0;
    }
    let d = (x.abs().log10().floor() + 1.0) as i32;
    let magnitude = 10_f64.powi(d - 6);
    (x / magnitude).round() * magnitude
}

/// Compares two real numbers with respect to the six most significant digits.
/// Returns "LT" if a < b, "EQ" if a == b, or "GT" if a > b.
fn realcompare(a: f64, b: f64) -> &'static str {
    let ra = round_to_6_sig(a);
    let rb = round_to_6_sig(b);
    if ra < rb {
        "LT"
    } else if ra > rb {
        "GT"
    } else {
        "EQ"
    }
}

/// Euclidean distance between two points.
fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

/// Triangle area from three points using the cross-product formula.
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0).abs()
}

/// Compute the angle at vertex (x2,y2) formed by points (x1,y1)-(x2,y2)-(x3,y3).
/// Returns None if vertex coincides with either endpoint.
fn angle_at_vertex(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    let d1 = dist(x1, y1, x2, y2);
    let d2 = dist(x3, y3, x2, y2);
    if realcompare(d1, 0.0) == "EQ" || realcompare(d2, 0.0) == "EQ" {
        return None;
    }
    let vx1 = x1 - x2;
    let vy1 = y1 - y2;
    let vx2 = x3 - x2;
    let vy2 = y3 - y2;
    let dot = vx1 * vx2 + vy1 * vy2;
    let mut cos_angle = dot / (d1 * d2);
    // Clamp to [-1, 1] to handle floating point errors
    if cos_angle > 1.0 {
        cos_angle = 1.0;
    }
    if cos_angle < -1.0 {
        cos_angle = -1.0;
    }
    Some(cos_angle.acos())
}

/// Determine which quadrant a point is in (1-based: I, II, III, IV).
/// Priority: I > II > III > IV for ambiguous cases.
fn quadrant(x: f64, y: f64) -> u8 {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

/// Check whether three points can be contained within or on a circle of given radius.
fn points_fit_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    // If all three points are the same, they fit in any circle with radius >= 0
    let d12 = dist(x1, y1, x2, y2);
    let d13 = dist(x1, y1, x3, y3);
    let d23 = dist(x2, y2, x3, y3);

    // Find the longest side
    let max_d = d12.max(d13).max(d23);

    // If the minimum enclosing circle is determined by a diameter (obtuse or right triangle),
    // then the radius is max_d / 2.
    // Otherwise (acute triangle), use circumradius.

    // Check if any single side's midpoint circle covers all three points
    // This happens when the triangle is obtuse or degenerate (collinear).
    let area = triangle_area(x1, y1, x2, y2, x3, y3);

    if realcompare(area, 0.0) == "EQ" {
        // Collinear or degenerate: minimum enclosing circle has diameter = max side
        let min_radius = max_d / 2.0;
        return realcompare(min_radius, radius) != "GT";
    }

    // For a proper triangle, check if obtuse:
    // Use the fact that for obtuse triangles, the circumradius > max_side/2,
    // but the minimum enclosing circle has radius = max_side/2 only if
    // the angle opposite the longest side is >= 90 degrees.
    //
    // Actually, for the minimum enclosing circle:
    // - If the triangle has an obtuse angle, the MEC is the circle with the longest side as diameter
    // - If the triangle is acute, the MEC is the circumscribed circle

    // Check if triangle is obtuse using the cosine rule on the largest side
    let (a_sq, b_sq, c_sq) = if max_d == d12 {
        (d12 * d12, d13 * d13, d23 * d23)
    } else if max_d == d13 {
        (d13 * d13, d12 * d12, d23 * d23)
    } else {
        (d23 * d23, d12 * d12, d13 * d13)
    };

    // Obtuse if a^2 >= b^2 + c^2 (angle opposite longest side >= 90 deg)
    if realcompare(a_sq, b_sq + c_sq) != "LT" {
        // Obtuse or right: MEC radius = max_d / 2
        let min_radius = max_d / 2.0;
        realcompare(min_radius, radius) != "GT"
    } else {
        // Acute triangle: MEC is circumscribed circle
        // Circumradius R = (a * b * c) / (4 * area)
        let circumradius = (d12 * d13 * d23) / (4.0 * area);
        realcompare(circumradius, radius) != "GT"
    }
}

/// Compute the CMV (Conditions Met Vector) from input data.
fn compute_cmv(input: &DecideInput) -> [bool; 15] {
    let n = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let p = &input.parameters;
    let mut cmv = [false; 15];

    // LIC 1: Two consecutive points farther apart than LENGTH1
    for i in 0..n - 1 {
        let d = dist(x[i], y[i], x[i + 1], y[i + 1]);
        if realcompare(d, p.length1) == "GT" {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2: Three consecutive points that cannot be contained in/on circle of RADIUS1
    for i in 0..n.saturating_sub(2) {
        if !points_fit_in_circle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], p.radius1) {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3: Three consecutive points forming an angle < (PI - EPSILON) or > (PI + EPSILON)
    for i in 0..n.saturating_sub(2) {
        if let Some(angle) = angle_at_vertex(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
            if realcompare(angle, PI - p.epsilon) == "LT" || realcompare(angle, PI + p.epsilon) == "GT" {
                cmv[2] = true;
                break;
            }
        }
    }

    // LIC 4: Three consecutive points forming a triangle with area > AREA1
    for i in 0..n.saturating_sub(2) {
        let area = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
        if realcompare(area, p.area1) == "GT" {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5: Q_PTS consecutive points lying in more than QUADS quadrants
    if n >= p.q_pts {
        for i in 0..=n - p.q_pts {
            let mut quads_seen = [false; 4];
            for j in 0..p.q_pts {
                let q = quadrant(x[i + j], y[i + j]);
                quads_seen[(q - 1) as usize] = true;
            }
            let count: usize = quads_seen.iter().filter(|&&v| v).count();
            if count > p.quads {
                cmv[4] = true;
                break;
            }
        }
    }

    // LIC 6: Two consecutive points where X[j] - X[i] < 0 (i = j-1)
    for i in 0..n - 1 {
        if realcompare(x[i + 1] - x[i], 0.0) == "LT" {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7: N_PTS consecutive points where at least one point is > DIST from the line
    // joining the first and last. Not met when NUMPOINTS < 3.
    if n >= 3 && n >= p.n_pts {
        for i in 0..=n - p.n_pts {
            let first = i;
            let last = i + p.n_pts - 1;
            let fx = x[first];
            let fy = y[first];
            let lx = x[last];
            let ly = y[last];
            let line_len = dist(fx, fy, lx, ly);

            for j in (first + 1)..last {
                let d = if realcompare(line_len, 0.0) == "EQ" {
                    // First and last coincide: distance from that point
                    dist(fx, fy, x[j], y[j])
                } else {
                    // Distance from point to line
                    let numerator = ((ly - fy) * x[j] - (lx - fx) * y[j] + lx * fy - ly * fx).abs();
                    numerator / line_len
                };
                if realcompare(d, p.dist) == "GT" {
                    cmv[6] = true;
                    break;
                }
            }
            if cmv[6] {
                break;
            }
        }
    }

    // LIC 8: Two points separated by exactly K_PTS intervening points,
    // distance > LENGTH1. Not met when NUMPOINTS < 3.
    if n >= 3 {
        for i in 0..n.saturating_sub(p.k_pts + 1) {
            let j = i + p.k_pts + 1;
            if j < n {
                let d = dist(x[i], y[i], x[j], y[j]);
                if realcompare(d, p.length1) == "GT" {
                    cmv[7] = true;
                    break;
                }
            }
        }
    }

    // LIC 9: Three points separated by A_PTS and B_PTS intervening points,
    // cannot be contained in/on circle of RADIUS1. Not met when NUMPOINTS < 5.
    if n >= 5 {
        for i in 0..n {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if k >= n {
                break;
            }
            if !points_fit_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], p.radius1) {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10: Three points separated by C_PTS and D_PTS intervening points,
    // forming angle < (PI - EPSILON) or > (PI + EPSILON). Not met when NUMPOINTS < 5.
    if n >= 5 {
        for i in 0..n {
            let j = i + p.c_pts + 1;
            let k = j + p.d_pts + 1;
            if k >= n {
                break;
            }
            if let Some(angle) = angle_at_vertex(x[i], y[i], x[j], y[j], x[k], y[k]) {
                if realcompare(angle, PI - p.epsilon) == "LT"
                    || realcompare(angle, PI + p.epsilon) == "GT"
                {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11: Three points separated by E_PTS and F_PTS intervening points,
    // forming a triangle with area > AREA1. Not met when NUMPOINTS < 5.
    if n >= 5 {
        for i in 0..n {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            if k >= n {
                break;
            }
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, p.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12: Two points separated by G_PTS intervening points,
    // X[j] - X[i] < 0. Not met when NUMPOINTS < 3.
    if n >= 3 {
        for i in 0..n {
            let j = i + p.g_pts + 1;
            if j >= n {
                break;
            }
            if realcompare(x[j] - x[i], 0.0) == "LT" {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13: Two points separated by K_PTS intervening points:
    // (a) distance > LENGTH1, AND (b) distance < LENGTH2. Not met when NUMPOINTS < 3.
    if n >= 3 {
        let mut cond_a = false;
        let mut cond_b = false;
        for i in 0..n {
            let j = i + p.k_pts + 1;
            if j >= n {
                break;
            }
            let d = dist(x[i], y[i], x[j], y[j]);
            if !cond_a && realcompare(d, p.length1) == "GT" {
                cond_a = true;
            }
            if !cond_b && realcompare(d, p.length2) == "LT" {
                cond_b = true;
            }
            if cond_a && cond_b {
                break;
            }
        }
        cmv[12] = cond_a && cond_b;
    }

    // LIC 14: Three points separated by A_PTS and B_PTS:
    // (a) cannot be contained in circle of RADIUS1, AND
    // (b) can be contained in circle of RADIUS2. Not met when NUMPOINTS < 5.
    if n >= 5 {
        let mut cond_a = false;
        let mut cond_b = false;
        for i in 0..n {
            let j = i + p.a_pts + 1;
            let k = j + p.b_pts + 1;
            if k >= n {
                break;
            }
            if !cond_a
                && !points_fit_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], p.radius1)
            {
                cond_a = true;
            }
            if !cond_b
                && points_fit_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], p.radius2)
            {
                cond_b = true;
            }
            if cond_a && cond_b {
                break;
            }
        }
        cmv[13] = cond_a && cond_b;
    }

    // LIC 15: Three points separated by E_PTS and F_PTS:
    // (a) triangle area > AREA1, AND (b) triangle area < AREA2. Not met when NUMPOINTS < 5.
    if n >= 5 {
        let mut cond_a = false;
        let mut cond_b = false;
        for i in 0..n {
            let j = i + p.e_pts + 1;
            let k = j + p.f_pts + 1;
            if k >= n {
                break;
            }
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if !cond_a && realcompare(area, p.area1) == "GT" {
                cond_a = true;
            }
            if !cond_b && realcompare(area, p.area2) == "LT" {
                cond_b = true;
            }
            if cond_a && cond_b {
                break;
            }
        }
        cmv[14] = cond_a && cond_b;
    }

    cmv
}

/// Compute the PUM from CMV, LCM, and diagonal PUM inputs.
fn compute_pum(cmv: &[bool; 15], input: &DecideInput) -> [[bool; 15]; 15] {
    let mut pum = [[false; 15]; 15];

    // Set diagonal elements from input
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }

    // Set off-diagonal elements based on LCM
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            let connector = input.lcm[i][j].as_str();
            pum[i][j] = match connector {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => false,
            };
        }
    }

    pum
}

/// Compute the FUV from the PUM.
fn compute_fuv(pum: &[[bool; 15]; 15]) -> [bool; 15] {
    let mut fuv = [false; 15];

    for i in 0..15 {
        if !pum[i][i] {
            // PUM diagonal is false: LIC not considered, FUV is true
            fuv[i] = true;
        } else {
            // Check if all elements in row i are true
            fuv[i] = pum[i].iter().all(|&v| v);
        }
    }

    fuv
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let cmv = compute_cmv(input);
    let pum = compute_pum(&cmv, input);
    let fuv = compute_fuv(&pum);
    let launch = fuv.iter().all(|&v| v);

    DecideOutput::from_fixed(cmv, pum, fuv, launch)
}
